import { createRouter, createWebHistory } from 'vue-router'

const routes = [
  {
    path: '',
    redirect: () => {
      return { path: '/home' }
    },
  },
  {
    path: '/frontend',
    redirect: () => {
      return { path: '/home' }
    },
  },
  {
    path: '/home',
    name: 'Home',
    component: () => import('@/pages/Home.vue'),
    meta: {
      title: 'MRV Tool',
    },
  },
  {
    path: '/new',
    name: 'WhataNew',
    component: () => import('@/pages/WhatsNew.vue'),
    meta: {
      title: "What's new",
    },
  },
  {
    name: 'About',
    path: '/about',
    component: () => import('@/pages/About.vue'),
    meta: {
      title: 'About MRV',
    },
  },
  {
    name: 'Project',
    path: '/project',
    component: () => import('@/pages/Projects.vue'),
    meta: {
      title: 'MRV Project',
    },
  },
  {
    name: 'Climate',
    path: '/climate-change-division',
    component: () => import('@/pages/ClimateChange.vue'),
    meta: {
      title: 'Climate Change Division',
    },
  },
  {
    name: 'Reports',
    path: '/reports',
    component: () => import('@/pages/Reports.vue'),
    meta: {
      title: 'MRV Report',
    },
  },
  {
    name: 'Support',
    path: '/support',
    component: () => import('@/pages/Support.vue'),
    meta: {
      title: 'MRV Support',
    },
  },
  {
    name: 'KnowledgeResource',
    path: '/knowledgeresource',
    component: () => import('@/pages/KnowledgeResource.vue'),
    meta: {
      title: 'Knowledge Resource',
    },
  },
  // Catch-all: unknown SPA routes silently rendered nothing (white screen)
  // because <router-view> had no fallback. Redirect to home instead.
  {
    path: '/:pathMatch(.*)*',
    redirect: { path: '/home' },
  },
]

let router = createRouter({
  history: createWebHistory('/frontend'),
  routes,

  scrollBehavior(to, from, savedPosition) {
    document.getElementById('app').scrollIntoView({ behavior: 'smooth' })
  },
})

router.beforeEach((to, from) => {
  document.title = to.meta?.title ?? 'MRV Tool'
})

export default router
